    public void readPlayerData(Player player) {
        CraftPlayer craftPlayer = (CraftPlayer) player;
        NBTTagCompound nbtTagCompound = craftPlayer.getHandle().save(new NBTTagCompound());

        // 获取存档数据中的各项信息
        double x = nbtTagCompound.getDouble("Pos")[0];
        double y = nbtTagCompound.getDouble("Pos")[1];
        double z = nbtTagCompound.getDouble("Pos")[2];

        // 进一步处理存档数据
